"""
Configuration management for project-sync.
"""

import os
import yaml
from pathlib import Path
from typing import List, Optional, Dict, Any
from dataclasses import dataclass, field


@dataclass
class SyncConfig:
    """同步配置类"""

    # 目标目录
    target: str = ""

    # 排除规则列表
    exclude: List[str] = field(default_factory=lambda: [
        ".psync",
        ".git",
        "__pycache__",
        "*.pyc",
        ".DS_Store",
        "Thumbs.db",
    ])

    # 包含规则列表（优先级高于排除）
    include: List[str] = field(default_factory=list)

    # 是否删除目标目录中源目录没有的文件
    delete_orphans: bool = False

    # 是否保留文件修改时间
    preserve_mtime: bool = True

    # 配置文件名
    CONFIG_FILE = ".psync"

    @classmethod
    def load(cls, project_dir: Path) -> "SyncConfig":
        """从项目目录加载配置"""
        config_path = project_dir / cls.CONFIG_FILE

        if not config_path.exists():
            raise FileNotFoundError(
                f"配置文件不存在: {config_path}\n"
                f"请先运行 'psync init' 创建配置文件"
            )

        with open(config_path, "r", encoding="utf-8") as f:
            data = yaml.safe_load(f) or {}

        config = cls()

        # 加载配置
        if "target" in data:
            config.target = data["target"]

        if "exclude" in data and isinstance(data["exclude"], list):
            # 合并默认排除规则和用户定义的排除规则
            config.exclude = list(set(config.exclude + data["exclude"]))

        if "include" in data and isinstance(data["include"], list):
            config.include = data["include"]

        if "delete_orphans" in data:
            config.delete_orphans = bool(data["delete_orphans"])

        if "preserve_mtime" in data:
            config.preserve_mtime = bool(data["preserve_mtime"])

        # 验证配置
        config.validate()

        return config

    def save(self, project_dir: Path) -> None:
        """保存配置到项目目录"""
        config_path = project_dir / self.CONFIG_FILE

        data = {
            "target": self.target,
            "exclude": self.exclude,
            "include": self.include if self.include else None,
            "delete_orphans": self.delete_orphans if self.delete_orphans else None,
            "preserve_mtime": self.preserve_mtime if not self.preserve_mtime else None,
        }

        # 移除 None 值
        data = {k: v for k, v in data.items() if v is not None}

        with open(config_path, "w", encoding="utf-8") as f:
            yaml.dump(data, f, default_flow_style=False, allow_unicode=True, sort_keys=False)

    def validate(self) -> None:
        """验证配置"""
        if not self.target:
            raise ValueError("目标目录 (target) 不能为空")

        # 检查目标目录是否存在
        target_path = Path(self.target)
        if not target_path.exists():
            # 尝试创建目标目录
            try:
                target_path.mkdir(parents=True, exist_ok=True)
            except Exception as e:
                raise ValueError(f"无法创建目标目录: {self.target}\n错误: {e}")

    def get_target_path(self) -> Path:
        """获取目标目录的 Path 对象"""
        return Path(self.target).resolve()

    def add_exclude(self, pattern: str) -> None:
        """添加排除规则"""
        if pattern not in self.exclude:
            self.exclude.append(pattern)

    def add_include(self, pattern: str) -> None:
        """添加包含规则"""
        if pattern not in self.include:
            self.include.append(pattern)

    def remove_exclude(self, pattern: str) -> bool:
        """移除排除规则"""
        if pattern in self.exclude:
            self.exclude.remove(pattern)
            return True
        return False

    def to_dict(self) -> Dict[str, Any]:
        """转换为字典"""
        return {
            "target": self.target,
            "exclude": self.exclude,
            "include": self.include,
            "delete_orphans": self.delete_orphans,
            "preserve_mtime": self.preserve_mtime,
        }
